import{_ as e,a as t,b as i,c as o,d as r}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as n,o as s,c as l,a2 as c}from"./chunks/framework.DnrXFDHb.js";const z=JSON.parse('{"title":"Aggiungere un canale OneDrive","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/upload/onedrive.md","filePath":"it-IT/upload/onedrive.md","lastUpdated":1781962217000}'),d={name:"it-IT/upload/onedrive.md"};function p(g,a,h,u,m,f){return s(),l("div",null,[...a[0]||(a[0]=[c('<h1 id="aggiungere-un-canale-onedrive" tabindex="-1">Aggiungere un canale OneDrive <a class="header-anchor" href="#aggiungere-un-canale-onedrive" aria-label="Permalink to &quot;Aggiungere un canale OneDrive&quot;">​</a></h1><h2 id="prima-di-iniziare" tabindex="-1">Prima di iniziare <a class="header-anchor" href="#prima-di-iniziare" aria-label="Permalink to &quot;Prima di iniziare&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>A cosa serve</th></tr></thead><tbody><tr><td>Account Microsoft</td><td>Per accedere alle pagine amministrative Microsoft e autorizzare OneDrive</td></tr><tr><td>Dominio ImgBed</td><td>Per l&#39;URL di callback OAuth</td></tr><tr><td>Registrazione app</td><td>Per generare <code>Client ID</code> e <code>Client Secret</code></td></tr><tr><td>Account OneDrive</td><td>Spazio effettivo in cui verranno salvati i file</td></tr></tbody></table><h2 id="configurazione" tabindex="-1">Configurazione <a class="header-anchor" href="#configurazione" aria-label="Permalink to &quot;Configurazione&quot;">​</a></h2><h3 id="passaggio-1-apri-microsoft-entra-id" tabindex="-1">Passaggio 1: apri Microsoft Entra ID <a class="header-anchor" href="#passaggio-1-apri-microsoft-entra-id" aria-label="Permalink to &quot;Passaggio 1: apri Microsoft Entra ID&quot;">​</a></h3><ol><li>Apri <code>portal.azure.com</code>.</li><li>Cerca <code>Microsoft Entra ID</code> in alto.</li><li>Se la pagina non compare nel menu, scegli:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Continue searching in Microsoft Entra ID</span></span></code></pre></div><ol start="4"><li>Apri <code>Microsoft Entra ID</code>.</li><li>Apri <code>App registrations</code>.</li><li>Clicca su <code>New registration</code>.</li></ol><h3 id="passaggio-2-registra-un-app" tabindex="-1">Passaggio 2: registra un&#39;app <a class="header-anchor" href="#passaggio-2-registra-un-app" aria-label="Permalink to &quot;Passaggio 2: registra un&#39;app&quot;">​</a></h3><p>Nella pagina <code>New registration</code>, compila:</p><table tabindex="0"><thead><tr><th>Campo</th><th>Cosa inserire</th></tr></thead><tbody><tr><td>Name</td><td>Un nome riconoscibile, per esempio <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>Scegli in base alla tabella sotto</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://your-domain.com/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>Guida al tipo di account:</p><table tabindex="0"><thead><tr><th>Scenario</th><th>Supported Account Types</th></tr></thead><tbody><tr><td>Solo OneDrive personale</td><td>Scegli l&#39;opzione per account Microsoft personali.</td></tr><tr><td>Account personali e lavoro/scuola</td><td>Scegli l&#39;opzione che supporta account personali e organizzativi.</td></tr><tr><td>Solo OneDrive aziendale o scolastico</td><td>Scegli l&#39;opzione per account organizzativi.</td></tr></tbody></table><p>Dopo aver compilato il modulo, clicca su registra.</p><p><img src="'+e+'" alt="Crea app OneDrive" loading="lazy"></p><h3 id="passaggio-3-copia-le-informazioni-dell-app" tabindex="-1">Passaggio 3: copia le informazioni dell&#39;app <a class="header-anchor" href="#passaggio-3-copia-le-informazioni-dell-app" aria-label="Permalink to &quot;Passaggio 3: copia le informazioni dell&#39;app&quot;">​</a></h3><p>Dalla pagina di riepilogo copia questi valori:</p><table tabindex="0"><thead><tr><th>Campo Microsoft</th><th>Campo ImgBed</th></tr></thead><tbody><tr><td><code>Application (client) ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Directory (tenant) ID</code></td><td><code>Tenant ID</code> per account organizzativi</td></tr></tbody></table><p><img src="'+t+'" alt="Application ID e Tenant ID" loading="lazy"></p><h3 id="passaggio-4-crea-un-client-secret" tabindex="-1">Passaggio 4: crea un Client Secret <a class="header-anchor" href="#passaggio-4-crea-un-client-secret" aria-label="Permalink to &quot;Passaggio 4: crea un Client Secret&quot;">​</a></h3><ol><li>Apri <code>Certificates &amp; secrets</code>.</li><li>Clicca su <code>New client secret</code>.</li><li>Inserisci una descrizione qualsiasi ma riconoscibile.</li><li>Scegli una scadenza.</li><li>Copia subito il <code>Value</code>, appena viene creato.</li></ol><p><img src="'+i+'" alt="Salva valore Client Secret" loading="lazy"></p><h3 id="passaggio-5-aggiungi-i-permessi-api" tabindex="-1">Passaggio 5: aggiungi i permessi API <a class="header-anchor" href="#passaggio-5-aggiungi-i-permessi-api" aria-label="Permalink to &quot;Passaggio 5: aggiungi i permessi API&quot;">​</a></h3><ol><li>Apri <code>API permissions</code>.</li><li>Clicca su <code>Add a permission</code>.</li><li>Scegli <code>Microsoft Graph</code>.</li><li>Scegli <code>Delegated permissions</code>.</li><li>Aggiungi questi permessi:</li></ol><table tabindex="0"><thead><tr><th>Permesso</th><th>Scopo</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>Carica file, crea cartelle ed elimina file</td></tr><tr><td><code>offline_access</code></td><td>Permette a ImgBed di ottenere un <code>Refresh Token</code></td></tr><tr><td><code>User.Read</code></td><td>Legge informazioni account e quota</td></tr></tbody></table><h3 id="passaggio-6-compila-il-canale-onedrive" tabindex="-1">Passaggio 6: compila il canale OneDrive <a class="header-anchor" href="#passaggio-6-compila-il-canale-onedrive" aria-label="Permalink to &quot;Passaggio 6: compila il canale OneDrive&quot;">​</a></h3><p>In Impostazioni di caricamento scegli <code>OneDrive</code> e compila:</p><table tabindex="0"><thead><tr><th>Campo ImgBed</th><th>Cosa inserire</th></tr></thead><tbody><tr><td>Nome canale</td><td>Un nome riconoscibile, per esempio <code>Main OneDrive</code></td></tr><tr><td>Client ID</td><td>La Microsoft <code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>Il <code>Client Secret Value</code> copiato</td></tr><tr><td>Tenant ID</td><td>Usa la tabella sotto</td></tr><tr><td>Refresh Token</td><td>Lascialo vuoto per ora</td></tr><tr><td>Directory radice</td><td>Opzionale. Default <code>imgbed</code>.</td></tr><tr><td>Nota</td><td>Opzionale</td></tr></tbody></table><p><img src="'+o+'" alt="Configura canale OneDrive" loading="lazy"></p><p>Come compilare <code>Tenant ID</code>:</p><table tabindex="0"><thead><tr><th>Tipo di account scelto</th><th><code>Tenant ID</code> in ImgBed</th></tr></thead><tbody><tr><td>Account personali</td><td><code>consumers</code></td></tr><tr><td>Account personali e organizzativi</td><td><code>common</code></td></tr><tr><td>Solo organizzazione corrente</td><td>La <code>Directory (tenant) ID</code></td></tr></tbody></table><h3 id="passaggio-7-ottieni-il-refresh-token" tabindex="-1">Passaggio 7: ottieni il Refresh Token <a class="header-anchor" href="#passaggio-7-ottieni-il-refresh-token" aria-label="Permalink to &quot;Passaggio 7: ottieni il Refresh Token&quot;">​</a></h3><ol><li>In ImgBed clicca su <code>Get Token</code>.</li><li>Accedi con l&#39;account Microsoft da collegare.</li><li>Approva la richiesta di autorizzazione.</li><li>La pagina di callback mostrerà un <code>Refresh Token</code>.</li><li>Copialo.</li><li>Torna in ImgBed e incollalo nel campo <code>Refresh Token</code>.</li></ol><p><img src="'+r+`" alt="Copia Refresh Token" loading="lazy"></p><h3 id="passaggio-8-salva-il-canale" tabindex="-1">Passaggio 8: salva il canale <a class="header-anchor" href="#passaggio-8-salva-il-canale" aria-label="Permalink to &quot;Passaggio 8: salva il canale&quot;">​</a></h3><p>Quando tutti i campi sono compilati, salva il canale.</p><h2 id="flusso-rapido" tabindex="-1">Flusso rapido <a class="header-anchor" href="#flusso-rapido" aria-label="Permalink to &quot;Flusso rapido&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Apri portal.azure.com</span></span>
<span class="line"><span>-&gt; Cerca Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; Apri App registrations</span></span>
<span class="line"><span>-&gt; Registra una nuova app</span></span>
<span class="line"><span>-&gt; Compila Name / Supported account types / Web redirect URI</span></span>
<span class="line"><span>-&gt; Registra</span></span>
<span class="line"><span>-&gt; Copia Application (client) ID</span></span>
<span class="line"><span>-&gt; Controlla l&#39;URL di callback in Authentication</span></span>
<span class="line"><span>-&gt; Crea un Client Secret in Certificates &amp; secrets</span></span>
<span class="line"><span>-&gt; Aggiungi i permessi in API permissions</span></span>
<span class="line"><span>-&gt; Inserisci Client ID / Client Secret / Tenant ID in ImgBed</span></span>
<span class="line"><span>-&gt; Clicca Get Token</span></span>
<span class="line"><span>-&gt; Copia il Refresh Token dalla pagina di callback</span></span>
<span class="line"><span>-&gt; Incollalo in ImgBed e salva</span></span></code></pre></div><h2 id="riferimenti" tabindex="-1">Riferimenti <a class="header-anchor" href="#riferimenti" aria-label="Permalink to &quot;Riferimenti&quot;">​</a></h2><ol><li>Registrazione app Microsoft Entra: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app</a></li><li>Authorization code flow Microsoft identity platform: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow</a></li><li>Autenticazione utente Microsoft Graph: <a href="https://learn.microsoft.com/en-us/graph/auth-v2-user" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/graph/auth-v2-user</a></li></ol>`,40)])])}const I=n(d,[["render",p]]);export{z as __pageData,I as default};
